queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?lounge a :Lounge .
    ?lounge p:name ?name .
    ?lounge p:Accessibility ?accessibility_f .
    FILTER(STR(?accessibility_f) = "All")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?observationdeck a :ObservationDeck .
    ?observationdeck p:name ?name .
    ?observationdeck p:Accessibility ?accessibility_f .
    FILTER(STR(?accessibility_f) = "All")
    BIND(?name AS ?o0)
  }
}

